// frontend/src/pages/Login.jsx
import { useState } from "react";
import { useNavigate } from "react-router-dom";
import { useAuth } from "../context/AuthContext";

export default function Login() {
  const [form, setForm] = useState({ email: "", password: "" });
  const [cargando, setCargando] = useState(false);
  const { login } = useAuth();
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setCargando(true);

    // BYPASS: Esperamos medio segundo para simular carga y entramos
    setTimeout(() => {
      // Usamos la función login del Contexto que ya tiene el usuario hardcodeado
      login("token-falso", { nombre: "Jorlin Developer", rol: "admin" });
      setCargando(false);
      navigate("/dashboard");
    }, 500);
  };

  return (
    <div className="card">
      <h2 style={{ textAlign: "center" }}>🧾 FactuApp</h2>
      <h3 style={{ textAlign: "center", color: "var(--text-muted)" }}>
        Bienvenido de nuevo
      </h3>

      <form onSubmit={handleSubmit}>
        <div style={{ marginBottom: "15px" }}>
          <label style={{ color: "var(--text-muted)", fontSize: "14px" }}>
            Email
          </label>
          <input
            type="email"
            placeholder="admin@empresa.com"
            value={form.email}
            onChange={(e) => setForm({ ...form, email: e.target.value })}
            required
          />
        </div>

        <div style={{ marginBottom: "20px" }}>
          <label style={{ color: "var(--text-muted)", fontSize: "14px" }}>
            Contraseña
          </label>
          <input
            type="password"
            placeholder="••••••••"
            value={form.password}
            onChange={(e) => setForm({ ...form, password: e.target.value })}
            required
          />
        </div>

        <button type="submit" disabled={cargando}>
          {cargando ? "Iniciando sesión..." : "Entrar al Sistema"}
        </button>
      </form>

      <p
        style={{
          textAlign: "center",
          fontSize: "12px",
          marginTop: "20px",
          color: "var(--text-muted)",
        }}
      >
        Modo de prueba activado (Bypass)
      </p>
    </div>
  );
}
